import React, { useEffect, useRef, useState } from "react";
import { applicantStausOptions, epochTogmt } from "src/utils/Common";
import { fetchAllApplicantData, fetchAllEnableJobPositionData } from "src/components/services/CareerApi";
import { tableApplicantsConstant } from "./tableApplicantsConstant";
import DataTable from "react-data-table-component";
import Select from 'react-select';
import { customStyles } from "../../../utils/tableCustomStyles";
import authService from "src/auth/auth.service";
import { CSVLink } from "react-csv";
import { useLocation } from "react-router-dom";
import GoBackComponent from "src/utils/GoBackComponent";

const headers = [
    { label: "First Name", key: "firstName" },
    { label: "Last Name", key: "lastName" },
    { label: "Job ID", key: "jobId" },
    { label: "Email", key: "email" },
    { label: "Country Code", key: "countryCode" },
    { label: "Phone No.", key: "phone" },
    { label: "Position", key: "positionName" },
    { label: "Position Type", key: "jobType" },
    { label: "Applied Date", key: "appliedDate" },
    { label: "Status", key: "status" }
];

function ApplicantList() {
    const location = useLocation();
    const [rowData, setRowData] = useState([]);
    const [status, setStatus] = useState({ label: "NEW", value: "NEW" });
    const [position, setPosition] = useState({});
    const [positionOptions, setPositionsOptions] = useState([]);
    const [perPage, setPerPage] = useState(10);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);
    const [exportData, setExportData] = useState([]);
    const [fileName, setFileName] = useState("");

    const csvLink = useRef()

    useEffect(() => {
        //getAllPositions();
        fetchApplicantList(1, 10);
    }, [status?.value]);

    const getAllPositions = async () => {
        let response = await fetchAllEnableJobPositionData();
        if (response?.code === 200) {
          let jobPosition = response.results && response.results.map((data) => { return { label: data.title, value: data._id } })
          setPositionsOptions(jobPosition);
        }
    };

    const fetchApplicantList = async (page, size) => {
        let data = {
            "status": status?.value, "page": page, "perPage": size
        }
        if (location?.state?.metaJobDescriptionId) {
            data.metaJobDescriptionId = location?.state?.metaJobDescriptionId;
        }
        const response = await fetchAllApplicantData(data);
        if (response?.code === 200) {
            setRowData(response?.results?.content);
            setLoading(false);
            setTotalRows(response?.results?.totalElements);
        }
    }

    const exportApplicantData = async () => {
        let data = {
            "status": status?.value, "page": 1, "perPage": 100
        }
        if (location?.state?.metaJobDescriptionId) {
            data.metaJobDescriptionId = location?.state?.metaJobDescriptionId;
        }
        let response = await fetchAllApplicantData(data);
        if (response?.code === 200) {
            let date = new Date();
            let dateMs = date.valueOf();
            const file = `applicant_list` + epochTogmt(dateMs) + "-" + dateMs + ".csv";
            let responseData = [];
            response?.results && response?.results && response?.results?.content?.map((data) => {
                responseData.push({ "firstName": data?.firstName, "lastName": data?.lastName, "email": data?.email, "countryCode": "+" + data?.countryCode, "phone": data?.phone, "positionName": data?.position, "jobType": data?.jobType === "FULL_TIME" ? "Full Time" : "Intern", "status": data?.status, "appliedDate": epochTogmt(data?.createTime), "jobId": data?.jobId })
            })
            setExportData(responseData);
            setFileName(file);
            setTimeout(() => {
                csvLink.current.link.click()
            }, 1000)
        }
    }

    const handleStatusChange = (data) => {
        setStatus(data)
    }

    const handlePageChange = page => {
        fetchApplicantList(page, perPage);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        setPerPage(newPerPage);
        fetchApplicantList(page, newPerPage);
    };

    const actionButton = () => {
        return (
            <React.Fragment>
                {authService.getPermission("APPLICANT_EXPORT_CSV") && rowData?.length > 0 && <a className="btn btn-primary" href={"javascript:void(0)"} onClick={() => exportApplicantData()} ><i class="fa-solid fa-download" /></a>}
            </React.Fragment>
        );
    };

    return (
        <>
            {location?.state?.jobDescriptionId && <GoBackComponent goBackData={`career/job-description-position/${location?.state?.jobDescriptionId}`} />}
            <div className='row'>
                <div className="col-md-12 mb-3">
                    <div className="filterSection">
                        {/* <div className="col-md-4" style={{ marginRight: "10px" }}>
                            <Select
                                options={positionOptions}
                                value={position?.value ? position : null}
                                placeholder={"Filter by position"}
                                onChange={handleStatusChange}
                                classNamePrefix="select"
                                styles={{
                                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                        const color = '#03a68059';
                                        return {
                                            ...styles,
                                            backgroundColor: isDisabled
                                                ? null
                                                : isSelected
                                                    ? '#03a68059'
                                                    : isFocused
                                                        ? '#03a68059'
                                                        : null,
                                            color: isDisabled
                                                ? '#ccc'
                                                : isSelected
                                                    ? color > 2
                                                        ? '#00374d'
                                                        : '#00374d'
                                                    : data.color,
                                            cursor: isDisabled ? 'not-allowed' : 'default',

                                            ':active': {
                                                ...styles[':active'],
                                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                            },
                                        };
                                    },
                                }}
                            />
                        </div> */}
                        <div className="col-md-3" style={{ marginRight: "10px" }}>
                            <Select
                                options={applicantStausOptions}
                                value={status}
                                placeholder={"Filter by status"}
                                onChange={handleStatusChange}
                                classNamePrefix="select"
                                styles={{
                                    option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                        const color = '#03a68059';
                                        return {
                                            ...styles,
                                            backgroundColor: isDisabled
                                                ? null
                                                : isSelected
                                                    ? '#03a68059'
                                                    : isFocused
                                                        ? '#03a68059'
                                                        : null,
                                            color: isDisabled
                                                ? '#ccc'
                                                : isSelected
                                                    ? color > 2
                                                        ? '#00374d'
                                                        : '#00374d'
                                                    : data.color,
                                            cursor: isDisabled ? 'not-allowed' : 'default',

                                            ':active': {
                                                ...styles[':active'],
                                                backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                            },
                                        };
                                    },
                                }}
                            />
                        </div>
                    </div>
                </div>
                <div className="col2Large">
                    <DataTable
                        title="Applicants"
                        columns={tableApplicantsConstant(fetchApplicantList)}
                        data={rowData}
                        customStyles={customStyles}
                        actions={actionButton()}
                        pagination
                        paginationPerPage={perPage}
                        pointerOnHover
                        fixedHeader
                        noContextMenu
                        fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                        progressPending={loading}
                        paginationServer
                        paginationTotalRows={totalRows}
                        onChangeRowsPerPage={handlePerRowsChange}
                        onChangePage={handlePageChange}
                    />
                </div>

                <CSVLink headers={headers} data={exportData} filename={fileName} ref={csvLink}></CSVLink>
                {/* <div className='col-sm-12'>
            <Link to={"/category/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create Category"}
                </CButton>
            </Link>
        </div> */}
            </div>
        </>
    )
}

export default ApplicantList;
